"use strict";(self.webpackChunkdocusaurus_knowledge_base=self.webpackChunkdocusaurus_knowledge_base||[]).push([[1872],{18502(e,t,i){i.r(t),i.d(t,{assets:()=>h,contentTitle:()=>o,default:()=>c,frontMatter:()=>s,metadata:()=>a,toc:()=>l});let a=JSON.parse('{"id":"6\u3001EY/IFRIC\uFF1ACompilation of Agenda Decisions/IFRS 9 Financial Instruments/hedging-variability-in-cash-flows-du-5d82ceea22","title":"Hedging Variability in Cash Flows due to Real Interest Rates (IFRS 9)","description":"May 2021","source":"@site/knowledge/6\u3001EY/IFRIC\uFF1ACompilation of Agenda Decisions/IFRS 9 Financial Instruments/Hedging Variability in Cash Flows due to Real Interest Rates (IFRS 9).md","sourceDirName":"6\u3001EY/IFRIC\uFF1ACompilation of Agenda Decisions/IFRS 9 Financial Instruments","slug":"/6-ey-bbb2f2ea9c/ifric-compilation-of-agenda-decision-fd4d0bbeaf/ifrs-9-financial-instruments-51656c8be6/hedging-variability-in-cash-flows-du-5d82ceea22","permalink":"/docs/6-ey-bbb2f2ea9c/ifric-compilation-of-agenda-decision-fd4d0bbeaf/ifrs-9-financial-instruments-51656c8be6/hedging-variability-in-cash-flows-du-5d82ceea22","draft":false,"unlisted":false,"tags":[],"version":"current","sidebarPosition":4,"frontMatter":{"id":"hedging-variability-in-cash-flows-du-5d82ceea22","title":"Hedging Variability in Cash Flows due to Real Interest Rates (IFRS 9)","slug":"/6-ey-bbb2f2ea9c/ifric-compilation-of-agenda-decision-fd4d0bbeaf/ifrs-9-financial-instruments-51656c8be6/hedging-variability-in-cash-flows-du-5d82ceea22","sidebar_position":4},"sidebar":"knowledgeSidebar","previous":{"title":"Fair Value Hedge of Foreign Currency Risk on Non-Financial Assets (IFRS 9)","permalink":"/docs/6-ey-bbb2f2ea9c/ifric-compilation-of-agenda-decision-fd4d0bbeaf/ifrs-9-financial-instruments-51656c8be6/fair-value-hedge-of-foreign-currency-25afdd6d0e"},"next":{"title":"Physical Settlement of Contracts to Buy or Sell a Non-financial Item (IFRS 9)","permalink":"/docs/6-ey-bbb2f2ea9c/ifric-compilation-of-agenda-decision-fd4d0bbeaf/ifrs-9-financial-instruments-51656c8be6/physical-settlement-of-contracts-to--8e19b89d27"}}');var n=i(74848),r=i(28453);let s={id:"hedging-variability-in-cash-flows-du-5d82ceea22",title:"Hedging Variability in Cash Flows due to Real Interest Rates (IFRS 9)",slug:"/6-ey-bbb2f2ea9c/ifric-compilation-of-agenda-decision-fd4d0bbeaf/ifrs-9-financial-instruments-51656c8be6/hedging-variability-in-cash-flows-du-5d82ceea22",sidebar_position:4},o="Hedging Variability in Cash Flows due to Real Interest Rates (IFRS 9)",h={},l=[{value:"Hedge accounting requirements in IFRS 9",id:"hedge-accounting-requirements-in-ifrs-9",level:2},{value:"Can a non-contractually specified real interest rate risk component be designated as the hedged item in the proposed cash flow hedging relationship?",id:"can-a-non-contractually-specified-real-interest-rate-risk-component-be-designated-as-the-hedged-item-in-the-proposed-cash-flow-hedging-relationship",level:2}];function d(e){let t={h1:"h1",h2:"h2",header:"header",p:"p",...(0,r.R)(),...e.components};return(0,n.jsxs)(n.Fragment,{children:[(0,n.jsx)(t.header,{children:(0,n.jsx)(t.h1,{id:"hedging-variability-in-cash-flows-due-to-real-interest-rates-ifrs-9",children:"Hedging Variability in Cash Flows due to Real Interest Rates (IFRS 9)"})}),"\n",(0,n.jsx)(t.p,{children:"May 2021"}),"\n",(0,n.jsx)(t.p,{children:"The Committee received a request about applying the hedge accounting requirements in IFRS 9 when the risk management objective is to \u2018fix\u2019 the cash flows in real terms."}),"\n",(0,n.jsx)(t.p,{children:"The request asked whether a hedge of the variability in cash flows arising from changes in the real interest rate, rather than the nominal interest rate, could be accounted for as a cash flow hedge. More specifically, the request describes a fact pattern in which an entity with a floating rate instrument referenced to an interest rate benchmark, such as LIBOR, enters into an inflation swap (which swaps the variable interest cash flows of the floating rate instrument for variable cash flows based on an inflation index). The request asked whether the entity can designate the swap in a cash flow hedging relationship to hedge changes in the variable interest payments for changes in the real interest rate."}),"\n",(0,n.jsx)(t.h2,{id:"hedge-accounting-requirements-in-ifrs-9",children:"Hedge accounting requirements in IFRS 9"}),"\n",(0,n.jsx)(t.p,{children:"Paragraph 6.1.1 of IFRS 9 states that the objective of hedge accounting is to represent, in the financial statements, the effect of an entity\u2019s risk management activities that use financial instruments to manage exposures arising from particular risks that could affect profit or loss (or other comprehensive income). Paragraph 6.4.1 of IFRS 9 sets out the qualifying criteria for hedge accounting."}),"\n",(0,n.jsx)(t.p,{children:"One type of hedging relationship described in paragraph 6.5.2 of IFRS 9 is a cash flow hedge in which an entity hedges the exposure to variability in cash flows that is attributable to a particular risk associated with all, or a component of, a recognised asset or liability and could affect profit or loss."}),"\n",(0,n.jsx)(t.p,{children:"Paragraph 6.3.7 of IFRS 9 specifies that an entity may designate an item in its entirety, or a component of an item, as a hedged item. A risk component may be designated as the hedged item if, based on an assessment within the context of the particular market structure, the risk component is separately identifiable and reliably measurable."}),"\n",(0,n.jsx)(t.p,{children:"With respect to inflation risk, paragraph B6.3.13 of IFRS 9 states \u2018there is a rebuttable presumption that unless inflation risk is contractually specified, it is not separately identifiable and reliably measurable and hence cannot be designated as a risk component of a financial instrument\u2019."}),"\n",(0,n.jsx)(t.p,{children:"Paragraph B6.3.14 of IFRS 9 states that an entity cannot simply impute the terms and conditions of an inflation hedging instrument by projecting its term and conditions onto a nominal interest rate debt instrument. This is because, when developing IFRS 9, the Board specifically considered inflation risk and put in place restrictions to address its concern that entities might impute the terms and conditions of a hedging instrument onto the hedged item \u2018without proper application of the criteria for designating risk components\u2019 as a hedged item (paragraph BC6.193 of IFRS 9). To appropriately account for hedge (in)effectiveness, paragraph B6.5.5 of IFRS 9 requires an entity to measure the (present) value of the hedged item independently of the measurement of the value of the hedging instrument."}),"\n",(0,n.jsx)(t.p,{children:"Given that the request asked whether the real interest rate component could be designated as a risk component in a cash flow hedge, the Committee\u2019s analysis focused on whether a non-contractually specified real interest rate risk component is separately identifiable and reliably measurable in the context of the proposed cash flow hedging relationship described in the request."}),"\n",(0,n.jsx)(t.h2,{id:"can-a-non-contractually-specified-real-interest-rate-risk-component-be-designated-as-the-hedged-item-in-the-proposed-cash-flow-hedging-relationship",children:"Can a non-contractually specified real interest rate risk component be designated as the hedged item in the proposed cash flow hedging relationship?"}),"\n",(0,n.jsx)(t.p,{children:"When considering the qualifying criteria in paragraph 6.4.1 of IFRS 9, the Committee observed that for cash flow hedge accounting to be applied in the fact pattern described in the request, it would be necessary to determine:"}),"\n",(0,n.jsx)(t.p,{children:"\u2022 whether that risk component is separately identifiable and reliably measurable as required by paragraph 6.3.7 of IFRS 9; and\n\u2022 as a result, that the entity has exposure to variability in cash flows that is attributable to the real interest rate risk component of the floating rate instrument as required by paragraph 6.5.2(b) of IFRS 9."}),"\n",(0,n.jsx)(t.p,{children:"The Committee noted that, to designate a risk component in a hedging relationship, the risk component must be separately identifiable and reliably measurable within the context of each individual hedging relationship. The Committee also noted that it is the market structure\u2014in which a floating rate instrument is issued and in which hedging activity will take place\u2014that needs to support the eligibility of a real interest rate risk component as a non-contractually specified risk component as required by paragraph 6.3.7 of IFRS 9. For the market structure to support the eligibility of that risk component in the proposed cash flow hedging relationship, the real interest rate must represent an identifiable pricing element in setting the floating benchmark interest rate, thereby creating separately identifiable and reliably measurable cash flow variability in the floating rate instrument."}),"\n",(0,n.jsx)(t.p,{children:"Although the rebuttable presumption in paragraph B6.3.13 of IFRS 9 applies to both fair value hedges and cash flow hedges, the example in paragraph B6.3.14 of IFRS 9 illustrates a rebuttal of the presumption in a fair value hedge. The Committee therefore concluded that, because nominal rates generally do not change as a direct result of changes in real interest rates, the existence in the relevant debt market of a term structure of zero-coupon real interest rates does not, in itself, overcome the rebuttable presumption in paragraph B6.3.13 of IFRS 9 in the proposed cash flow hedging relationship."}),"\n",(0,n.jsx)(t.p,{children:"The Committee noted that cash flows as defined by paragraph 6 of IAS 7 Statement of Cash Flows are, by nature, denominated in nominal terms. The Committee also noted that the interest rate for floating rate financial instruments is defined in nominal terms for a given currency. Therefore, to meet the requirements in IFRS 9 for a cash flow hedge designation, the variability in the cash flows of the floating rate instrument attributable to the designated risk component needs to be assessed in nominal terms. A nominal interest rate (such as LIBOR) may be influenced by expected inflation and the real interest rate in the long term. However, nominal interest rates do not change as a direct result of changes in inflation or the real interest rate (that is, they are not identifiable pricing elements in setting nominal rates)."}),"\n",(0,n.jsx)(t.p,{children:"The Committee therefore concluded that there is no exposure to variability in cash flows that is attributable to changes in the real interest rate in the proposed cash flow hedging relationship and, thus, the requirements in paragraph 6.3.7 and paragraph 6.5.2(b) of IFRS 9 are not met. Consequently, the real interest rate risk component in the proposed cash flow hedging relationship does not meet the requirements in IFRS 9 to be designated as an eligible hedged item as required by paragraph 6.4.1 of IFRS 9."}),"\n",(0,n.jsx)(t.p,{children:"The Committee concluded that the requirements in IFRS 9 provide an adequate basis for an entity to determine whether a hedge of the variability in cash flows arising from changes in the real interest rate, rather than the nominal interest rate, could be accounted for as a cash flow hedge. Consequently, the Committee decided not to add a standard-setting project to the work plan."})]})}function c(e={}){let{wrapper:t}={...(0,r.R)(),...e.components};return t?(0,n.jsx)(t,{...e,children:(0,n.jsx)(d,{...e})}):d(e)}},28453(e,t,i){i.d(t,{R:()=>s,x:()=>o});var a=i(96540);let n={},r=a.createContext(n);function s(e){let t=a.useContext(r);return a.useMemo(function(){return"function"==typeof e?e(t):{...t,...e}},[t,e])}function o(e){let t;return t=e.disableParentContext?"function"==typeof e.components?e.components(n):e.components||n:s(e.components),a.createElement(r.Provider,{value:t},e.children)}}}]);